{
  "sentences": [
    {
      "text": "我肚子餓，所以想吃飯。",
      "pinyin": "Wǒ dùzi è, suǒyǐ xiǎng chī fàn.",
      "pinyin_numeric": "wo3 du4zi e4, suo3yi3 xiang3 chi1 fan4.",
      "translation_en": "I'm hungry, so I want to eat.",
      "translation_ko": "배가 고파서 밥을 먹고 싶어요."
    },
    {
      "text": "我口渴，所以想喝一杯水。",
      "pinyin": "Wǒ kǒukě, suǒyǐ xiǎng hē yī bēi shuǐ.",
      "pinyin_numeric": "wo3 kou3ke3, suo3yi3 xiang3 he1 yi1 bei1 shui3.",
      "translation_en": "I'm thirsty, so I want to drink a glass of water.",
      "translation_ko": "목이 말라서 물 한 잔을 마시고 싶어요."
    },
    {
      "text": "我感冒了，所以想休息。",
      "pinyin": "Wǒ gǎnmào le, suǒyǐ xiǎng xiūxi.",
      "pinyin_numeric": "wo3 gan3mao4 le0, suo3yi3 xiang3 xiu1xi0.",
      "translation_en": "I have a cold, so I want to rest.",
      "translation_ko": "감기에 걸려서 쉬고 싶어요."
    },
    {
      "text": "我頭痛，所以不想看書。",
      "pinyin": "Wǒ tóutòng, suǒyǐ bù xiǎng kàn shū.",
      "pinyin_numeric": "wo3 tou2tong4, suo3yi3 bu4 xiang3 kan4 shu1.",
      "translation_en": "I have a headache, so I don't want to read.",
      "translation_ko": "머리가 아파서 책을 읽고 싶지 않아요."
    },
    {
      "text": "我沒睡飽，所以不想去上班。",
      "pinyin": "Wǒ méi shuì bǎo, suǒyǐ bù xiǎng qù shàngbān.",
      "pinyin_numeric": "wo3 mei2 shui4 bao3, suo3yi3 bu4 xiang3 qu4 shang4ban1.",
      "translation_en": "I didn't sleep enough, so I don't want to go to work.",
      "translation_ko": "잠을 충분히 못 자서 출근하고 싶지 않아요."
    },
    {
      "text": "我太累了，所以想喝咖啡。",
      "pinyin": "Wǒ tài lèi le, suǒyǐ xiǎng hē kāfēi.",
      "pinyin_numeric": "wo3 tai4 lei4 le0, suo3yi3 xiang3 he1 ka1fei1.",
      "translation_en": "I'm too tired, so I want to drink coffee.",
      "translation_ko": "너무 피곤해서 커피를 마시고 싶어요."
    },
    {
      "text": "下雨了，所以不想走路。",
      "pinyin": "Xià yǔ le, suǒyǐ bù xiǎng zǒulù.",
      "pinyin_numeric": "xia4 yu3 le0, suo3yi3 bu4 xiang3 zou3lu4.",
      "translation_en": "It's raining, so I don't want to walk.",
      "translation_ko": "비가 와서 걷고 싶지 않아요."
    },
    {
      "text": "塞車了，所以想坐捷運。",
      "pinyin": "Sāichē le, suǒyǐ xiǎng zuò jiéyùn.",
      "pinyin_numeric": "sai1che1 le0, suo3yi3 xiang3 zuo4 jie2yun4.",
      "translation_en": "There's a traffic jam, so I want to take the MRT.",
      "translation_ko": "차가 막혀서 지하철을 타고 싶어요."
    },
    {
      "text": "我忘了帶錢，所以不想買東西。",
      "pinyin": "Wǒ wàng le dài qián, suǒyǐ bù xiǎng mǎi dōngxī.",
      "pinyin_numeric": "wo3 wang4 le0 dai4 qian2, suo3yi3 bu4 xiang3 mai3 dong1xi1.",
      "translation_en": "I forgot to bring money, so I don't want to buy anything.",
      "translation_ko": "돈을 가져오는 걸 잊어서 물건을 사고 싶지 않아요."
    },
    {
      "text": "我想省錢，所以不想喝咖啡。",
      "pinyin": "Wǒ xiǎng shěng qián, suǒyǐ bù xiǎng hē kāfēi.",
      "pinyin_numeric": "wo3 xiang3 sheng3 qian2, suo3yi3 bu4 xiang3 he1 ka1fei1.",
      "translation_en": "I want to save money, so I don't want to drink coffee.",
      "translation_ko": "돈을 아끼고 싶어서 커피를 마시고 싶지 않아요."
    }
  ]
}
